define("local_vbs_schedule/calendar",["core/ajax","core/notification","core/pending","core/log"],function(Ajax,Notification,Pending,Log){"use strict";const SELECTORS={ROOT:"[data-region=\"vbs-schedule-calendar\"]",CONTAINER:"[data-region=\"calendar-container\"]",PERIOD:"[data-region=\"current-period\"]",VIEW_INPUTS:"[name=\"vbs-viewmode\"]",TYPE_INPUTS:"[name=\"vbs-type\"]",COURSE:"[data-filter=\"course\"]",DATE_FROM:"[data-filter=\"datefrom\"]",DATE_TO:"[data-filter=\"dateto\"]",APPLY:"[data-action=\"apply-filter\"]",NAV_PREV:"[data-action=\"nav-prev\"]",NAV_NEXT:"[data-action=\"nav-next\"]",NAV_TODAY:"[data-action=\"nav-today\"]"};let root=null;const state={viewmode:"month",year:0,month:0,weekStart:null,courseid:0,types:["class","exam"],datefrom:0,dateto:0};const init=(options)=>{root=document.querySelector(SELECTORS.ROOT);if(!root)return;const now=new Date();state.viewmode=options.viewmode||"month";state.year=now.getFullYear();state.month=now.getMonth();state.weekStart=getWeekStart(now);if(options.showclass&&!options.showexam){state.types=["class"];checkRadio("#type-class");}else if(!options.showclass&&options.showexam){state.types=["exam"];checkRadio("#type-exam");}else{state.types=["class","exam"];checkRadio("#type-both");}initDefaultDates();bindEvents();renderCalendar();};const checkRadio=(sel)=>{const el=root.querySelector(sel);if(el)el.checked=true;};const initDefaultDates=()=>{const now=new Date();const first=new Date(now.getFullYear(),now.getMonth(),1);const last=new Date(now.getFullYear(),now.getMonth()+1,0);setDateInput(SELECTORS.DATE_FROM,first);setDateInput(SELECTORS.DATE_TO,last);state.datefrom=toUnixStart(first);state.dateto=toUnixEnd(last);};const setDateInput=(sel,date)=>{const el=root.querySelector(sel);if(el)el.value=toDateInputValue(date);};const toDateInputValue=(date)=>{const y=date.getFullYear();const m=String(date.getMonth()+1).padStart(2,"0");const d=String(date.getDate()).padStart(2,"0");return`${y}-${m}-${d}`;};const toUnixStart=(date)=>Math.floor(new Date(date.getFullYear(),date.getMonth(),date.getDate(),0,0,0).getTime()/1000);const toUnixEnd=(date)=>Math.floor(new Date(date.getFullYear(),date.getMonth(),date.getDate(),23,59,59).getTime()/1000);const getWeekStart=(date)=>{const d=new Date(date.getFullYear(),date.getMonth(),date.getDate());const dow=d.getDay();const diff=(dow===0)?-6:1-dow;d.setDate(d.getDate()+diff);return d;};const formatTime=(ts)=>{const d=new Date(ts*1000);return`${String(d.getHours()).padStart(2,"0")}:${String(d.getMinutes()).padStart(2,"0")}`;};const formatDate=(date)=>`${date.getDate()}/${date.getMonth()+1}/${date.getFullYear()}`;const escHtml=(str)=>{if(!str)return"";return str.replace(/&/g,"&amp;").replace(/</g,"&lt;").replace(/>/g,"&gt;").replace(/"/g,"&quot;");};const bindEvents=()=>{root.querySelectorAll(SELECTORS.VIEW_INPUTS).forEach(input=>{input.addEventListener("change",()=>{state.viewmode=input.value;savePref();renderCalendar();});});root.querySelectorAll(SELECTORS.TYPE_INPUTS).forEach(input=>{input.addEventListener("change",()=>{state.types=(input.value==="both")?["class","exam"]:[input.value];savePref();});});const courseEl=root.querySelector(SELECTORS.COURSE);if(courseEl)courseEl.addEventListener("change",()=>{state.courseid=parseInt(courseEl.value,10)||0;});const applyBtn=root.querySelector(SELECTORS.APPLY);if(applyBtn)applyBtn.addEventListener("click",applyFilter);root.querySelector(SELECTORS.NAV_PREV)?.addEventListener("click",navPrev);root.querySelector(SELECTORS.NAV_NEXT)?.addEventListener("click",navNext);root.querySelector(SELECTORS.NAV_TODAY)?.addEventListener("click",navToday);};const applyFilter=()=>{const fromEl=root.querySelector(SELECTORS.DATE_FROM);const toEl=root.querySelector(SELECTORS.DATE_TO);if(fromEl?.value)state.datefrom=toUnixStart(new Date(fromEl.value));if(toEl?.value)state.dateto=toUnixEnd(new Date(toEl.value));renderCalendar();};const navPrev=()=>{if(state.viewmode==="month"){if(state.month===0){state.month=11;state.year--;}else state.month--;const first=new Date(state.year,state.month,1);const last=new Date(state.year,state.month+1,0);state.datefrom=toUnixStart(first);state.dateto=toUnixEnd(last);syncDateInputsFromState();}else if(state.viewmode==="week"){const d=new Date(state.weekStart);d.setDate(d.getDate()-7);state.weekStart=d;const end=new Date(state.weekStart);end.setDate(end.getDate()+6);state.datefrom=toUnixStart(state.weekStart);state.dateto=toUnixEnd(end);syncDateInputsFromState();}else{const span=state.dateto-state.datefrom;state.datefrom-=(span+1);state.dateto-=(span+1);syncDateInputsFromState();}renderCalendar();};const navNext=()=>{if(state.viewmode==="month"){if(state.month===11){state.month=0;state.year++;}else state.month++;const first=new Date(state.year,state.month,1);const last=new Date(state.year,state.month+1,0);state.datefrom=toUnixStart(first);state.dateto=toUnixEnd(last);syncDateInputsFromState();}else if(state.viewmode==="week"){const d=new Date(state.weekStart);d.setDate(d.getDate()+7);state.weekStart=d;const end=new Date(state.weekStart);end.setDate(end.getDate()+6);state.datefrom=toUnixStart(state.weekStart);state.dateto=toUnixEnd(end);syncDateInputsFromState();}else{const span=state.dateto-state.datefrom;state.datefrom+=(span+1);state.dateto+=(span+1);syncDateInputsFromState();}renderCalendar();};const navToday=()=>{const now=new Date();state.year=now.getFullYear();state.month=now.getMonth();state.weekStart=getWeekStart(now);initDefaultDates();renderCalendar();};const syncDateInputsFromState=()=>{setDateInput(SELECTORS.DATE_FROM,new Date(state.datefrom*1000));setDateInput(SELECTORS.DATE_TO,new Date(state.dateto*1000));};const updatePeriodLabel=()=>{const el=root.querySelector(SELECTORS.PERIOD);if(!el)return;const names=["Tháng 1","Tháng 2","Tháng 3","Tháng 4","Tháng 5","Tháng 6","Tháng 7","Tháng 8","Tháng 9","Tháng 10","Tháng 11","Tháng 12"];if(state.viewmode==="month"){el.textContent=`${names[state.month]} ${state.year}`;}else if(state.viewmode==="week"){const end=new Date(state.weekStart);end.setDate(end.getDate()+6);el.textContent=`${formatDate(state.weekStart)} – ${formatDate(end)}`;}else{el.textContent=`${formatDate(new Date(state.datefrom*1000))} – ${formatDate(new Date(state.dateto*1000))}`;}};const getApiDateRange=()=>{if(state.viewmode==="month"){const f=new Date(state.year,state.month,1);const l=new Date(state.year,state.month+1,0);return{datefrom:toUnixStart(f),dateto:toUnixEnd(l)};}if(state.viewmode==="week"){const end=new Date(state.weekStart);end.setDate(end.getDate()+6);return{datefrom:toUnixStart(state.weekStart),dateto:toUnixEnd(end)};}return{datefrom:state.datefrom,dateto:state.dateto};};const fetchEvents=(datefrom,dateto)=>Ajax.call([{methodname:"local_vbs_schedule_get_events",args:{userid:0,datefrom,dateto,courseid:state.courseid,types:state.types}}])[0];const renderCalendar=async()=>{const pending=new Pending("local_vbs_schedule/calendar:render");const container=root.querySelector(SELECTORS.CONTAINER);showSpinner(container);updatePeriodLabel();const{datefrom,dateto}=getApiDateRange();try{const result=await fetchEvents(datefrom,dateto);const events=result.events||[];if(state.viewmode==="month")renderMonth(container,events);else if(state.viewmode==="week")renderWeek(container,events);else renderList(container,events);}catch(err){Notification.exception(err);}finally{pending.resolve();}};const showSpinner=(container)=>{container.innerHTML='<div class="d-flex justify-content-center p-5"><div class="spinner-border text-primary" role="status"><span class="visually-hidden">Loading…</span></div></div>';};const renderMonth=(container,events)=>{const firstDay=new Date(state.year,state.month,1);const daysInMonth=new Date(state.year,state.month+1,0).getDate();const byDate={};events.forEach(ev=>{const d=new Date(ev.starttime*1000);const key=`${d.getFullYear()}-${d.getMonth()}-${d.getDate()}`;(byDate[key]=byDate[key]||[]).push(ev);});const today=new Date();const todayKey=`${today.getFullYear()}-${today.getMonth()}-${today.getDate()}`;const dayHeaders=["T2","T3","T4","T5","T6","T7","CN"];const dow=firstDay.getDay();const leading=(dow===0)?6:dow-1;let cells="";for(let i=0;i<leading;i++)cells+='<div class="vbs-month-cell vbs-month-cell--other"></div>';for(let day=1;day<=daysInMonth;day++){const key=`${state.year}-${state.month}-${day}`;const isToday=(key===todayKey);const evList=byDate[key]||[];const dayClass=`vbs-month-cell${isToday?" vbs-month-cell--today":""}`;const numClass=isToday?"vbs-month-cell-day vbs-today-badge":"vbs-month-cell-day";const pills=evList.slice(0,3).map(ev=>`<div class="vbs-event-pill" style="background:${ev.color}" title="${escHtml(ev.title)}"><span class="vbs-event-pill-text">${escHtml(ev.title)}</span></div>`).join("");const more=evList.length>3?`<div class="vbs-event-more">+${evList.length-3} th\xEAm</div>`:"";cells+=`<div class="${dayClass}"><div class="${numClass}">${day}</div>${pills}${more}</div>`;}container.innerHTML=`<div class="vbs-month-view"><div class="vbs-month-header">${dayHeaders.map(h=>`<div class="vbs-month-dayname">${h}</div>`).join("")}</div><div class="vbs-month-grid">${cells}</div></div>`;};const renderWeek=(container,events)=>{const days=[];for(let i=0;i<7;i++){const d=new Date(state.weekStart);d.setDate(d.getDate()+i);days.push(d);}const today=new Date();const todayKey=`${today.getFullYear()}-${today.getMonth()}-${today.getDate()}`;const byDate={};events.forEach(ev=>{const d=new Date(ev.starttime*1000);const key=`${d.getFullYear()}-${d.getMonth()}-${d.getDate()}`;(byDate[key]=byDate[key]||[]).push(ev);});const dayNames=["T2","T3","T4","T5","T6","T7","CN"];const headerCols=days.map((d,i)=>{const key=`${d.getFullYear()}-${d.getMonth()}-${d.getDate()}`;const isToday=(key===todayKey);return`<div class="vbs-week-col-header${isToday?" vbs-today-header":""}"><div class="vbs-week-dayname">${dayNames[i]}</div><div class="vbs-week-daynum${isToday?" vbs-today-badge":""}">${d.getDate()}</div></div>`;}).join("");const bodyCols=days.map(d=>{const key=`${d.getFullYear()}-${d.getMonth()}-${d.getDate()}`;const evList=byDate[key]||[];const evHtml=evList.map(ev=>`<div class="vbs-week-event" style="border-left:4px solid ${ev.color}"><div class="vbs-week-event-time">${formatTime(ev.starttime)}</div><div class="vbs-week-event-title">${escHtml(ev.title)}</div>${ev.location?`<div class="vbs-week-event-loc">${escHtml(ev.location)}</div>`:""}</div>`).join("");return`<div class="vbs-week-col">${evHtml}</div>`;}).join("");container.innerHTML=`<div class="vbs-week-view"><div class="vbs-week-header">${headerCols}</div><div class="vbs-week-body">${bodyCols}</div></div>`;};const renderList=(container,events)=>{if(!events.length){container.innerHTML='<div class="vbs-empty-state text-center py-5"><i class="fa fa-calendar-times fa-3x text-muted mb-3" aria-hidden="true"></i><p class="text-muted mb-0">Kh\xF4ng c\xF3 sự kiện trong khoảng thời gian n\xE0y.</p></div>';return;}const rows=events.map(ev=>{const start=new Date(ev.starttime*1000);const badge=ev.type==="class"?"primary":"danger";const typeStr=ev.type==="class"?"Lịch học":"Lịch thi";return`<tr><td><div class="fw-semibold">${formatDate(start)}</div><small class="text-muted">${formatTime(ev.starttime)} – ${formatTime(ev.endtime)}</small></td><td><span class="badge bg-${badge} me-1">${typeStr}</span>${escHtml(ev.title)}${ev.instructor?`<div><small class="text-muted">GV: ${escHtml(ev.instructor)}</small></div>`:""}</td><td><small>${escHtml(ev.location||"—")}</small></td><td><span class="badge bg-secondary text-capitalize">${escHtml(ev.status)}</span></td></tr>`;}).join("");container.innerHTML=`<div class="table-responsive"><table class="table table-hover align-middle"><thead class="table-light"><tr><th>Thời gian</th><th>Sự kiện</th><th>Địa điểm</th><th>Trạng th\xE1i</th></tr></thead><tbody>${rows}</tbody></table></div>`;};const savePref=()=>{Ajax.call([{methodname:"local_vbs_schedule_save_pref",args:{view_mode:state.viewmode,show_class:state.types.includes("class"),show_exam:state.types.includes("exam")}}])[0].catch(err=>Log.error("vbs_schedule: failed to save pref",err));};return{init};});
